const body = $input.first().json.body || $input.first().json;
const db06_id = (body.db06_id || body.id || '').toString().replace(/-/g, '');
if (!db06_id) throw new Error('missing db06_id');
return [{ json: { db06_id } }];

const p = $input.first().json;
const TARGET_RELS = ["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"];
let target_id = '', target_rel = '';
for (const rel of TARGET_RELS) {
  const arr = p.properties[rel]?.relation || [];
  if (arr.length) { target_id = (arr[0].id||'').replace(/-/g,''); target_rel = rel; break; }
}
return [{ json: {
  db06_id: p.id.replace(/-/g, ''),
  ai_mode: p.properties['ai模式']?.select?.name || '',
  execute_idea_db06: p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '',
  mingxi_content: p.properties['明細內容']?.rich_text?.map(t=>t.plain_text).join('') || '',
  db05_id: target_id,
  target_rel: target_rel,
  mingxi_name: p.properties['明細名稱']?.title?.map(t=>t.plain_text).join('') || '',
  sort_num: p.properties['排序']?.number
}}];

const baton = $('Parse DB06').first().json;
const target = $input.first().json;
const tp = target.properties || {};
const titleProp = Object.values(tp).find(v=>v&&v.type==='title');
const target_name = (titleProp?.title||[]).map(t=>t.plain_text).join('') || '(未命名)';
const rt = k => (tp[k]?.rich_text||[]).map(t=>t.plain_text).join('');
const cur_idea = rt('執行構想');
const analysis = rt('分析備註');
const summary = rt('簡介摘要');
const theme = rt('主題名稱');
const tgt_exec_note = rt('執行備註') || '';
const XF=['提案引用','管考引用','項目引用','協作引用','內容引用','明細引用','庫存引用','對象引用','日期引用'];
let xc=0; for(const f of XF) xc += ((tp[f]&&tp[f].relation)||[]).length;
const own_idea = baton.execute_idea_db06 || '';
const REL2DB={'對應提案':1,'對應管考':2,'對應項目':3,'對應協作':4,'對應內容':5,'對應庫存':7,'對應對象':8,'對應標籤':8,'對應地點':8,'對應提供對象':8};
const tdb=REL2DB[baton.target_rel]||0;
const childDBs=(tdb>=1&&tdb<=5)?[]:null;
let allowed=[]; if(tdb>=1&&tdb<=5){ for(let x=tdb+1;x<=6;x++) allowed.push('DB0'+x); }
const childRule = allowed.length ? ('本 target 屬 DB0'+tdb+'，建子頁只能往下建：'+allowed.join('/')+'。提案其他 DB = 違規，不要提。') : ('本 target 不在從屬鏈下游可建範圍，建子頁提案一律回空陣列 []。');

const inv = '【素材盤點】
X引用連到的資料參考：'+xc+' 筆
分析備註：'+(analysis?('已有 '+analysis.length+' 字'):'(空，尚未被分析)')+'
現有執行構想：'+(cur_idea?(cur_idea.length+' 字'):'(空)')+'
主題名稱：'+(theme||'(空)')+'　簡介摘要：'+(summary?'已有':'(空)');
const system = "你是 makesense（現思文化創藝有限公司，宜蘭在地文化事業）嗨嗨家族的嗨嗨企劃（規劃師）。職責：把 target 的目標輪廓變成可執行架構，寫進 target 的執行構想。
== 工作方式 ==
先看素材盤點，把規劃推進到「現有素材能支撐的解析度」：
- 素材近空（資料參考 0-2 筆）→ 粗 scope：寫 3-6 段結構化方向，並抽 3-8 個對應標籤候選關鍵詞（人名/地名/事件/主題短語）供搜查採集。
- 素材部分到位 → 章節雛形：列章節骨架，缺的素材標「待補」。
- 素材齊備（資料參考多筆＋有分析備註）→ 細結構：執行構想推進成含 markdown ## 章節標題的完整企劃版，每章標目標字數與素材方向；並填主題名稱（4-12字）、簡介摘要（60-100字）。
長文（預估>8000字）：逐章自足，每個 ## 章標目標字數（2000-4000字/章）、素材方向、與前後章銜接點。
== 鐵律 ==
1. 本次執行構想（四九對企劃的特別交辦）優先於通用規格。
2. 「執行構想新增段」只回新增的內容，不要重複現有全文 —— 系統會自動把你的新增段接到原文後面。
3. 素材未齊的部分寫「待補方向」，不硬編。
4. 一律繁體中文，具體可查證。
== 建子頁 ==
若判斷此 target 需要拆成數個下級子頁（只能沿從屬鏈往下：提案DB01→管考DB02→項目DB03→協作DB04→內容DB05→明細DB06），在「建子頁提案」列出，每個含 DB/暫定標題/理由/欄位組合。不需要就回空陣列 []。實際建頁會由四九逐一按按鈕同意，你只提案。
== 只回合法 JSON ==
{"execution_summary":"做了什麼/素材盤點結果/未做什麼","主題名稱":"後期才填，否則空字串","簡介摘要":"後期才填，否則空字串","執行構想新增段":"3-5句方向或完整章節版，不含原文","對應標籤候選":["關鍵詞"],"建子頁提案":[{"DB":"DB04","暫定標題":"...","理由":"一句話","欄位組合":"例:協作類別=辦理活動、活動選項=講座課程"}],"needs_human_intervention":false}";
const user = '【建子頁方向限制】'+childRule+'

target 名稱：'+target_name+'

'+inv+'

【現有執行構想全文】
'+(cur_idea||'(空)')+'

【本棒執行構想 — 四九對企劃這一棒的特別交辦】
'+(own_idea||'(空)')+'

【上輪嗨嗨檢核成果紀錄】
'+(tgt_exec_note||'(尚未有檢核記錄)')+'

依素材盤點決定規劃解析度，回 JSON。';
return [{ json: { system, user, cur_idea, target_name, target_id: baton.db05_id, db06_id: baton.db06_id, ai_mode: baton.ai_mode||'企劃', sort_num: baton.sort_num, target_rel: baton.target_rel, allowed_child_dbs: allowed } }];

const resp = $input.first().json;
const ctx = $('Build Claude prompt').first().json;
const text = resp.content?.[0]?.text || '';
const usage = resp.usage || {};
let p; try { const m=text.match(/\{[\s\S]*\}/); p=m?JSON.parse(m[0]):{} ; } catch(e){ p={}; }
const newSeg = (p['執行構想新增段']||'').toString().trim();
const d=new Date(); const tw=new Date(d.getTime()+8*3600*1000);
const ts=tw.getUTCFullYear()+'-'+String(tw.getUTCMonth()+1).padStart(2,'0')+'-'+String(tw.getUTCDate()).padStart(2,'0')+' '+String(tw.getUTCHours()).padStart(2,'0')+':'+String(tw.getUTCMinutes()).padStart(2,'0');
const cur = ctx.cur_idea || '';
const full = newSeg ? ((cur?cur+'\n\n':'')+'── '+ts+' 企劃 ──\n'+newSeg) : cur;
const chunk = s => { const a=[]; for(let i=0;i<s.length;i+=2000) a.push({text:{content:s.slice(i,i+2000)}}); return a.length?a:[{text:{content:''}}]; };
const target_props = {};
if (full) target_props['執行構想'] = { rich_text: chunk(full) };
const theme=(p['主題名稱']||'').toString().trim();
if(theme){ if(ctx.target_rel==='對應提案'){ target_props['專案名稱']={title:[{text:{content:theme.slice(0,200)}}]}; } else { target_props['主題名稱']={rich_text:[{text:{content:theme.slice(0,200)}}]}; } }
const sm=(p['簡介摘要']||'').toString().trim(); if(sm) target_props['簡介摘要']={rich_text:[{text:{content:sm.slice(0,1900)}}]};
const tags = Array.isArray(p['對應標籤候選'])?p['對應標籤候選'].slice(0,8):[];
let subpages = Array.isArray(p['建子頁提案'])?p['建子頁提案'].slice(0,8):[];
const allowed=new Set(ctx.allowed_child_dbs||[]);
subpages = subpages.filter(s=>s&&s['暫定標題']&&allowed.has((s['DB']||'').toString()));
const it=parseInt(usage.input_tokens||0), ot=parseInt(usage.output_tokens||0);
const cost=((it*0.8+ot*4)/1000000*32).toFixed(2);
const usage_line='進='+it+' 出='+ot+' 成本NT'+cost;
const exec_summary=(p.execution_summary||'企劃完成').toString();
let exec_note='── '+ts+' 企劃 ──\n'+exec_summary;
if(tags.length) exec_note+='\n對應標籤候選(給搜查):'+tags.join('、');
if(subpages.length) exec_note+='\n建子頁提案 '+subpages.length+' 個(已發 Telegram 待四九逐一確認)';
exec_note=exec_note.slice(0,1990);
const sanitize=s=>(s||'').toString().replace(/[\/\\:<>#@\[\]\{\}\|\^`\*_~"']/g,' ').replace(/\s+/g,' ').trim().slice(0,500);
const wk=Object.keys(target_props);
return [{ json: { db06_id:ctx.db06_id, db05_id:ctx.target_id, target_id:ctx.target_id, ai_mode:ctx.ai_mode, sort_num:ctx.sort_num,
  target_props, subpages, exec_note, usage_line, safe_summary:sanitize(exec_note),
  preview_text:'企劃寫入 '+(wk.join('、')||'無')+(subpages.length?(' | 建子頁提案 '+subpages.length+' 個待確認'):''), validator_warning:'' } }];

const pc = $('Parse Claude').first().json;
const subs = pc.subpages || [];
let sent = 0;
const NHEAD={'Authorization':'Bearer '+$env.NOTION_INTEGRATION_TOKEN,'Notion-Version':'2022-06-28','Content-Type':'application/json'};
if (subs.length) {
  try {
    await this.helpers.httpRequest({method:'PATCH',url:'https://api.notion.com/v1/pages/'+pc.db06_id,headers:NHEAD,body:JSON.stringify({properties:{'明細內容':{rich_text:[{text:{content:JSON.stringify(subs).slice(0,1990)}}]}}})});
  } catch(e) {}
  const base='https://makesense.zeabur.app/webhook/db06-subpage-create';
  for (let i=0;i<subs.length;i++) {
    const s=subs[i];
    const msg='🧩 嗨嗨企劃建議新增子頁 '+(i+1)+'/'+subs.length+'\n暫定標題：'+(s['暫定標題']||'')+'\n屬於：'+(s['DB']||'')+'\n理由：'+(s['理由']||'')+'\n欄位組合：'+(s['欄位組合']||'(未指定)')+'\n\n按 OK 建這頁；OK ALL 連後面的一起建；有意見就別按、或 reply 這則訊息。';
    const kb={inline_keyboard:[[{text:'✅ OK（建這頁）',url:base+'?db06='+pc.db06_id+'&idx='+i},{text:'⏩ OK ALL（這頁+剩下全部）',url:base+'?db06='+pc.db06_id+'&idx='+i+'&all=1'}]]};
    try {
      await this.helpers.httpRequest({method:'POST',url:'https://api.telegram.org/bot'+$env.TELEGRAM_BOT_TOKEN+'/sendMessage',headers:{'Content-Type':'application/json'},body:JSON.stringify({chat_id:8523155253,text:msg,reply_markup:kb})});
      sent++;
    } catch(e) {}
  }
}
return [{ json: { ...pc, subpage_msgs_sent:sent } }];

const row=$input.first().json||{};
const pc=$('Parse Claude').first().json;
const auto_mode=row.auto_mode===true;
const reply_to=parseInt(row.last_msg_id||0)||0;
const result_msg='✅ 第 '+(pc.sort_num!=null?pc.sort_num:'?')+' 棒 ('+(pc.ai_mode||'')+') 已完成
DB06 '+pc.db06_id+'

'+(pc.safe_summary||'')+(pc.usage_line?('
tokens '+pc.usage_line):'')+'

📄 target 頁面：https://www.notion.so/'+(pc.db05_id||'').replace(/-/g,'');
return [{json:{auto_mode,reply_to,flow_id:pc.db05_id,db05_id:pc.db05_id,db06_id:pc.db06_id,sort_num:pc.sort_num,ai_mode:pc.ai_mode,result_msg}}];

