const results = $input.first().json.results || [];
const g = $('Build gateB').first().json;
const total = results.length;
const done = results.filter(p=>(p.properties['ai狀態']?.status?.name||'')==='完成').length;
const pending = results.filter(p => (p.properties['ai狀態']?.status?.name||'') !== '完成');
if (pending.length === 0) {
  return [{ json: { has_next:false, tg_done:'🎉 全套完成 — 共 '+total+' 棒已全部跑完。' } }];
}
const p = pending[0];
const nid = p.id.replace(/-/g,'');
const nmode = p.properties['ai模式']?.select?.name || '';
const nidea = (p.properties['執行構想']?.rich_text||[]).map(t=>t.plain_text).join('').slice(0,600) || '(未填)';
const nsort = p.properties['排序']?.number;
const _b='https://makesense.zeabur.app/webhook/';
let runner_url;
if (nmode.includes('聯想')) runner_url=_b+'db06-lianxiang-traversal';
else if (nmode.includes('搜查')) runner_url=_b+'db06-search';
else if (nmode.includes('分析')) runner_url=_b+'db06-analyze';
else if (nmode.includes('文案')) runner_url=_b+'db06-copy';
else if (nmode.includes('檢核')) runner_url=_b+'db06-check';
else runner_url=_b+'db06-plan';
const gateA = '🛫 關卡A 執行前確認\n第 '+(nsort!=null?nsort:'?')+' 棒 ('+nmode+')。全套 '+total+' 棒,已完成 '+done+' 棒。\nDB06 '+nid+'\n\n本棒預定執行構想:\n'+nidea+'\n\n按 OK 放行這一棒,按 OK ALL 之後全自動。要 redo 重跑請打字 reply。\n📄 本棒頁面：https://www.notion.so/'+nid+'\ngateA db06='+nid;
return [{ json: { has_next:true, db06_id:nid, runner_url, gateA, cb_ok:'A1:'+nid, cb_all:'AA:'+nid } }];
